PostToolUse.powershell:
$h = [Console]::In.ReadToEnd() | ConvertFrom-Json
$file = $h.tool_input.file_path
if (-not $file -or $file -notlike '*.go') { exit 0 }
if (-not (Test-Path go.mod)) { exit 0 }
if (-not (Get-Command goimports -ErrorAction SilentlyContinue)) { exit 0 }
goimports -w $file
exit $LASTEXITCODE
